#include <unistd.h>

pthread_mutex_t mtx;

void *low_priority(void *arg) {
    (void)arg;
    pthread_mutex_lock(&mtx);
    printf("Low: lock acquis\n");
    usleep(200000);
    printf("Low: travail termine\n");
    pthread_mutex_unlock(&mtx);
    return NULL;
}

void *high_priority(void *arg) {
    (void)arg;
    usleep(50000);
    printf("High: tentative lock\n");
    pthread_mutex_lock(&mtx);
    printf("High: lock acquis\n");
    pthread_mutex_unlock(&mtx);
    return NULL;
}

int main(void) {
    pthread_mutexattr_t attr;
    pthread_mutexattr_init(&attr);
    pthread_mutexattr_setprotocol(&attr, PTHREAD_PRIO_INHERIT);
    pthread_mutex_init(&mtx, &attr);
    pthread_mutexattr_destroy(&attr);

    pthread_t tl, th;
    pthread_create(&tl, NULL, low_priority, NULL);
    pthread_create(&th, NULL, high_priority, NULL);
    pthread_join(tl, NULL);
    pthread_join(th, NULL);
    printf("Protocole: PRIO_INHERIT\n");
    printf("Inversion resolue\n");
    pthread_mutex_destroy(&mtx);
    return 0;
}

